// ─── WF-06: Análise do Funil ───
// Processa o board e gera uma lista de ações a executar

const board = $input.first().json;
const agora = new Date();
const actions = [];

// Configuração de thresholds (em horas)
const THRESHOLD_FOLLOWUP = 48;      // 48h sem interação → mover para follow_up
const THRESHOLD_PERDA = 168;         // 7 dias → mover para perda
const THRESHOLD_COBRANCA = 120;      // 5 dias sem resposta em proposta_enviada

function horasDesde(dateStr) {
  if (!dateStr) return 0;
  const dt = new Date(dateStr);
  return (agora - dt) / (1000 * 60 * 60);
}

if (!board.stages || board.stages.length === 0) {
  return [{ json: { actions: [], resumo: 'Nenhuma etapa encontrada no funil.' } }];
}

for (const stage of board.stages) {
  const stageId = stage.id;
  const leads = stage.leads || [];

  for (const lead of leads) {
    const horas = horasDesde(lead.data_chegada || lead.created_at);

    // ─── Regra 1: nova_oportunidade > 48h → follow_up ───
    if (stageId === 'nova_oportunidade' && horas >= THRESHOLD_FOLLOWUP && horas < THRESHOLD_PERDA) {
      // Mover para follow_up
      actions.push({
        tipo: 'move',
        descricao: `Mover ${lead.nome} para follow_up (${Math.round(horas)}h sem interação)`,
        entry_id: lead.entry_id,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: `/api/pipeline/entries/${lead.entry_id}/move`,
        method: 'PUT',
        body: { etapa_id: 'follow_up' }
      });
      // Criar tarefa de follow-up
      actions.push({
        tipo: 'task',
        descricao: `Tarefa: Follow-up ${lead.nome}`,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: '/api/tasks',
        method: 'POST',
        body: {
          titulo: `Follow-up: ${lead.nome}`,
          descricao: `Lead sem interação há ${Math.round(horas)} horas. Fazer contato.`,
          lead_id: lead.lead_id,
          tipo: 'automatica'
        }
      });
      // Nota no histórico
      actions.push({
        tipo: 'note',
        descricao: `Nota: ${lead.nome} movido automaticamente`,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: `/api/pipeline/history/${lead.lead_id}/note?descricao=${encodeURIComponent('Movido automaticamente para follow-up (' + Math.round(horas) + 'h sem interação)')}`,
        method: 'POST',
        body: null
      });
    }

    // ─── Regra 2: nova_oportunidade > 7 dias → perda ───
    if (stageId === 'nova_oportunidade' && horas >= THRESHOLD_PERDA) {
      actions.push({
        tipo: 'move',
        descricao: `Mover ${lead.nome} para perda (${Math.round(horas)}h)`,
        entry_id: lead.entry_id,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: `/api/pipeline/entries/${lead.entry_id}/move`,
        method: 'PUT',
        body: { etapa_id: 'perda' }
      });
      actions.push({
        tipo: 'update_lead',
        descricao: `Marcar ${lead.nome} como perda`,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: `/api/leads/${lead.lead_id}`,
        method: 'PUT',
        body: { status_venda: 'perda' }
      });
    }

    // ─── Regra 3: proposta_enviada > 5 dias → cobrar resposta ───
    if (stageId === 'proposta_enviada' && horas >= THRESHOLD_COBRANCA) {
      actions.push({
        tipo: 'task',
        descricao: `Tarefa: Cobrar resposta de ${lead.nome}`,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: '/api/tasks',
        method: 'POST',
        body: {
          titulo: `Cobrar resposta: ${lead.nome}`,
          descricao: `Proposta enviada há ${Math.round(horas)} horas sem resposta.`,
          lead_id: lead.lead_id,
          tipo: 'automatica'
        }
      });
      actions.push({
        tipo: 'note',
        descricao: `Nota: Cobrança criada para ${lead.nome}`,
        lead_id: lead.lead_id,
        lead_nome: lead.nome,
        endpoint: `/api/pipeline/history/${lead.lead_id}/note?descricao=${encodeURIComponent('Tarefa de cobrança criada automaticamente (' + Math.round(horas) + 'h sem resposta)')}`,
        method: 'POST',
        body: null
      });
    }
  }
}

// Se não há ações, retornar item vazio para parar o fluxo
if (actions.length === 0) {
  return [{ json: { skip: true, resumo: 'Funil processado: nenhuma ação necessária.' } }];
}

// Retornar cada ação como um item separado para o SplitInBatches
return actions.map(a => ({ json: a }));

// Resumo final das ações executadas
const items = $input.all();
const total = items.length;

const resumo = `Funil processado: ${total} ação(ões) executada(s).`;

return [{ json: { resumo, total_acoes: total, timestamp: new Date().toISOString() } }];
